import PropertyCard from "./Components/PropertyCard";   


function Home() {
    return (
        <div>
            <section>
                <h1>Seek your Perfect Home</h1>
            </section>

            <section>
                <h2>Featured Listing</h2>
                <div>
                    {properties.map((properties)=>( <PropertyCard key={property.id} property={property} />))}
                </div>
            </section>
        </div>
    );

}

export default Home;
